parameters.bodyParametersJson:
{
  "model": "gpt-4-turbo-preview",
  "messages": [
    {
      "role": "system",
      "content": "You are an assistant that classifies user feedback into three categories: Bug, Feature Request, or Question. Respond with ONLY a JSON object with 'category' and 'confidence' (0-1) fields. Example: {\"category\": \"Bug\", \"confidence\": 0.95}"
    },
    {
      "role": "user",
      "content": "{{ $json.body.feedback_text }}"
    }
  ],
  "temperature": 0.3
}

parameters.functionCode:
// Parse AI response
const content = $json.body.choices[0].message.content;
const classification = JSON.parse(content);

// Map category to GitHub label
const categoryMap = {
  'Bug': 'bug',
  'Feature Request': 'enhancement',
  'Question': 'question'
};

return {
  category: classification.category,
  label: categoryMap[classification.category],
  confidence: classification.confidence,
  feedback_text: $json.body.feedback_text,
  user_id: $json.body.user_id,
  user_email: $json.body.user_email,
  app_version: $json.body.app_version,
  device_info: $json.body.device_info,
  timestamp: new Date().toISOString()
};

